class EmailService:
    def __init__(self) -> None:
        self.settings = get_settings()

    def _check_smtp_config(self) -> None:
        if (
            not self.settings.smtp_host
            or not self.settings.smtp_username
            or not self.settings.smtp_password
            or not self.settings.smtp_from_email
        ):
            raise EmailDeliveryError("SMTP settings are not configured.")

    def _send(self, *, to_email: str, subject: str, html: str, plain: str) -> None:
        msg = MIMEMultipart("alternative")
        msg["Subject"] = subject
        msg["From"] = self.settings.smtp_from_email
        msg["To"] = to_email
        msg.attach(MIMEText(plain, "plain"))
        msg.attach(MIMEText(html, "html"))
        try:
            with smtplib.SMTP(self.settings.smtp_host, self.settings.smtp_port, timeout=30) as smtp:
                smtp.starttls()
                smtp.login(self.settings.smtp_username, self.settings.smtp_password)
                smtp.send_message(msg)
        except Exception as exc:
            raise EmailDeliveryError("Unable to deliver email.") from exc

    def send_verification_email(self, *, to_email: str, verification_url: str) -> None:
        self._check_smtp_config()
        expires_minutes = int(self.settings.verification_token_expire_minutes)
        html = (
            VERIFICATION_TEMPLATE.replace("{logo}", SAGE_LOGO_B64)
            .replace("{verification_url}", verification_url)
            .replace("{expires_minutes}", str(expires_minutes))
        )
        plain = "\n".join([
            "Welcome to Sage AI.",
            "",
            "Please verify your email address by opening this link:",
            verification_url,
            "",
            f"This link expires in {expires_minutes} minutes.",
            "If you did not create an account, you can safely ignore this email.",
        ])
        self._send(to_email=to_email, subject="Verify your Sage AI account", html=html, plain=plain)

    def send_password_reset_email(self, *, to_email: str, reset_url: str) -> None:
        self._check_smtp_config()
        expires_minutes = int(self.settings.verification_token_expire_minutes)
        html = (
            RESET_PASSWORD_TEMPLATE.replace("{logo}", SAGE_LOGO_B64)
            .replace("{reset_url}", reset_url)
            .replace("{expires_minutes}", str(expires_minutes))
        )
        plain = "\n".join([
            "You requested a password reset for your Sage AI account.",
            "",
            "Click the link below to reset your password:",
            reset_url,
            "",
            f"This link expires in {expires_minutes} minutes.",
            "If you did not request this, you can safely ignore this email.",
        ])
        self._send(to_email=to_email, subject="Reset your Sage AI password", html=html, plain=plain)
